import { describe, expect, it } from 'vitest';
import { twinParadox, twinParadoxMultiLeg } from './twin-paradox';
import { lorentzGamma } from './simultaneity';

// ─── Helpers ────────────────────────────────────────────────────────

/** 1 year in picolorenzos. 1 pLo = pi days. */
const PLO_PER_YEAR = 365.25 / Math.PI;

/** Convert years to picolorenzos. */
function yearsToPLo(years: number): number {
  return years * PLO_PER_YEAR;
}

// ─── twinParadox (symmetric round trip) ─────────────────────────────

describe('twinParadox', () => {
  it('basic trip to Proxima Centauri at 0.5c', () => {
    const result = twinParadox({ targetDistanceLy: 4.24, travelBeta: 0.5 });

    expect(result.source).toBe('GnosisTwinParadox');
    expect(result.targetDistanceLy).toBe(4.24);
    expect(result.travelBeta).toBe(0.5);

    // Coordinate time = 2 * 4.24 / 0.5 = 16.96 years
    const expectedCoordYears = 2 * 4.24 / 0.5; // 16.96
    const expectedCoordPLo = yearsToPLo(expectedCoordYears);
    expect(result.stationaryTwin.totalCoordinateTimePLo).toBeCloseTo(expectedCoordPLo, 3);

    // gamma at 0.5c
    const gamma = lorentzGamma(0.5);
    expect(result.gamma).toBeCloseTo(gamma, 6);
    expect(gamma).toBeCloseTo(1.1547, 3);

    // Traveler proper time = coordinate / gamma ~ 14.69 years
    const expectedTravelerYears = expectedCoordYears / gamma;
    expect(expectedTravelerYears).toBeCloseTo(14.69, 1);

    // Age difference ~ 2.27 years
    const expectedDiffYears = expectedCoordYears - expectedTravelerYears;
    expect(result.ageDifferenceYears).toBeCloseTo(expectedDiffYears, 1);
    expect(expectedDiffYears).toBeCloseTo(2.27, 1);
  });

  it('dramatic dilation at 0.99c', () => {
    const result = twinParadox({ targetDistanceLy: 4.24, travelBeta: 0.99 });

    const gamma = lorentzGamma(0.99);
    expect(gamma).toBeCloseTo(7.089, 2);

    // Coordinate time = 2 * 4.24 / 0.99 ~ 8.566 years
    const coordYears = 2 * 4.24 / 0.99;
    // Traveler proper = coord / gamma ~ 1.208 years
    const travelerYears = coordYears / gamma;
    const diffYears = coordYears - travelerYears;

    expect(result.ageDifferenceYears).toBeCloseTo(diffYears, 1);
    // Difference should be large (> 7 years)
    expect(result.ageDifferenceYears).toBeGreaterThan(7);
  });

  it('near-Newtonian at 0.1c', () => {
    const result = twinParadox({ targetDistanceLy: 4.24, travelBeta: 0.1 });

    const gamma = lorentzGamma(0.1);
    // gamma at 0.1c is very close to 1
    expect(gamma).toBeCloseTo(1.005, 2);

    // Age difference should be tiny
    expect(result.ageDifferenceYears).toBeGreaterThan(0);
    expect(result.ageDifferenceYears).toBeLessThan(1);
  });

  it('stationary proper time equals total coordinate time', () => {
    const result = twinParadox({ targetDistanceLy: 10, travelBeta: 0.8 });

    expect(result.stationaryTwin.totalProperTimePLo).toBe(
      result.stationaryTwin.totalCoordinateTimePLo
    );
  });

  it('traveler proper time < stationary proper time (always)', () => {
    for (const beta of [0.1, 0.3, 0.5, 0.7, 0.9, 0.99]) {
      const result = twinParadox({ targetDistanceLy: 5, travelBeta: beta });
      expect(result.travelingTwin.totalProperTimePLo).toBeLessThan(
        result.stationaryTwin.totalProperTimePLo
      );
    }
  });

  it('timeDilationRatio < 1 for any nonzero beta', () => {
    for (const beta of [0.01, 0.1, 0.5, 0.9, 0.999]) {
      const result = twinParadox({ targetDistanceLy: 1, travelBeta: beta });
      expect(result.timeDilationRatio).toBeLessThan(1);
      expect(result.timeDilationRatio).toBeGreaterThan(0);
    }
  });

  it('age difference is always positive', () => {
    for (const beta of [0.05, 0.5, 0.95]) {
      const result = twinParadox({ targetDistanceLy: 3, travelBeta: beta });
      expect(result.ageDifferencePLo).toBeGreaterThan(0);
      expect(result.ageDifferenceYears).toBeGreaterThan(0);
    }
  });

  it('both twins reunite at the same coordinate time (same pLo)', () => {
    const result = twinParadox({ targetDistanceLy: 4.24, travelBeta: 0.6 });

    // Stationary twin's single leg ends at the total coordinate time
    const stationaryEnd = result.stationaryTwin.legs[0].endPLo;
    // Traveling twin's last leg ends at the total coordinate time
    const travelingEnd =
      result.travelingTwin.legs[result.travelingTwin.legs.length - 1].endPLo;

    expect(stationaryEnd).toBeCloseTo(travelingEnd, 9);
  });

  it('both twins start at the same pLo (departure)', () => {
    const result = twinParadox({ targetDistanceLy: 4.24, travelBeta: 0.6 });

    expect(result.stationaryTwin.legs[0].startPLo).toBe(0);
    expect(result.travelingTwin.legs[0].startPLo).toBe(0);
  });

  it('traveling twin has two legs (outbound + return)', () => {
    const result = twinParadox({ targetDistanceLy: 4.24, travelBeta: 0.5 });

    expect(result.travelingTwin.legs).toHaveLength(2);
    expect(result.travelingTwin.legs[0].direction).toBe('outbound');
    expect(result.travelingTwin.legs[1].direction).toBe('return');
  });

  it('outbound leg ends where return leg starts (spatial continuity)', () => {
    const result = twinParadox({ targetDistanceLy: 10, travelBeta: 0.7 });

    const outbound = result.travelingTwin.legs[0];
    const ret = result.travelingTwin.legs[1];

    expect(outbound.endX).toBeCloseTo(ret.startX, 9);
    expect(outbound.endPLo).toBeCloseTo(ret.startPLo, 9);
  });

  it('return leg ends at x = 0 (home)', () => {
    const result = twinParadox({ targetDistanceLy: 4.24, travelBeta: 0.8 });

    const ret = result.travelingTwin.legs[1];
    expect(ret.endX).toBeCloseTo(0, 9);
  });
});

// ─── twinParadoxMultiLeg ────────────────────────────────────────────

describe('twinParadoxMultiLeg', () => {
  it('two-leg multi matches single round trip when legs are symmetric', () => {
    const single = twinParadox({ targetDistanceLy: 5, travelBeta: 0.6 });
    const multi = twinParadoxMultiLeg([
      { distanceLy: 5, beta: 0.6 },
      { distanceLy: 5, beta: 0.6 },
    ]);

    expect(multi.travelingTwin.totalProperTimePLo).toBeCloseTo(
      single.travelingTwin.totalProperTimePLo,
      6
    );
    expect(multi.ageDifferenceYears).toBeCloseTo(single.ageDifferenceYears, 6);
  });

  it('asymmetric legs give different proper time than single equivalent', () => {
    // Two legs at different speeds vs one equivalent trip
    const multi = twinParadoxMultiLeg([
      { distanceLy: 5, beta: 0.3 },
      { distanceLy: 5, beta: 0.9 },
    ]);

    // Single trip at average-ish speed would give different proper time
    const single = twinParadox({ targetDistanceLy: 5, travelBeta: 0.6 });

    // They should NOT match -- broken geodesic at different speeds
    // accumulates time differently
    expect(multi.travelingTwin.totalProperTimePLo).not.toBeCloseTo(
      single.travelingTwin.totalProperTimePLo,
      1
    );
  });

  it('age difference is always positive for multi-leg', () => {
    const result = twinParadoxMultiLeg([
      { distanceLy: 3, beta: 0.4 },
      { distanceLy: 2, beta: 0.7 },
      { distanceLy: 1, beta: 0.2 },
      { distanceLy: 6, beta: 0.95 },
    ]);

    expect(result.ageDifferencePLo).toBeGreaterThan(0);
    expect(result.ageDifferenceYears).toBeGreaterThan(0);
  });

  it('traveler proper time < stationary proper time for multi-leg', () => {
    const result = twinParadoxMultiLeg([
      { distanceLy: 10, beta: 0.5 },
      { distanceLy: 10, beta: 0.8 },
    ]);

    expect(result.travelingTwin.totalProperTimePLo).toBeLessThan(
      result.stationaryTwin.totalProperTimePLo
    );
  });

  it('timeDilationRatio < 1 for multi-leg', () => {
    const result = twinParadoxMultiLeg([
      { distanceLy: 1, beta: 0.2 },
      { distanceLy: 1, beta: 0.9 },
    ]);

    expect(result.timeDilationRatio).toBeLessThan(1);
    expect(result.timeDilationRatio).toBeGreaterThan(0);
  });

  it('legs chain temporally (no gaps)', () => {
    const result = twinParadoxMultiLeg([
      { distanceLy: 3, beta: 0.5 },
      { distanceLy: 4, beta: 0.7 },
      { distanceLy: 2, beta: 0.3 },
    ]);

    const legs = result.travelingTwin.legs;
    for (let i = 1; i < legs.length; i++) {
      expect(legs[i].startPLo).toBeCloseTo(legs[i - 1].endPLo, 9);
    }
  });

  it('total coordinate time equals sum of leg coordinate times', () => {
    const result = twinParadoxMultiLeg([
      { distanceLy: 5, beta: 0.4 },
      { distanceLy: 3, beta: 0.6 },
    ]);

    const legSum = result.travelingTwin.legs.reduce(
      (sum, leg) => sum + leg.coordinateTimePLo,
      0
    );
    expect(result.travelingTwin.totalCoordinateTimePLo).toBeCloseTo(legSum, 9);
  });
});
